sys_script.script:
// Check if this is a new policy application
var catItem = current.cat_item.toString();
if (catItem && current.cat_item.name && current.cat_item.name.toString().indexOf('New Insurance Policy') > -1) {

    // Get catalog item variables
    var variables = {};
    var variableGR = new GlideRecord('sc_item_option_mtom');
    variableGR.addQuery('request_item', current.getUniqueValue());
    variableGR.query();

    while (variableGR.next()) {
        var varName = variableGR.sc_item_option.name.toString();
        var varValue = variableGR.getValue('value');
        variables[varName] = varValue;
    }

    // Create new insurance client record
    var insuranceGR = new GlideRecord('x_1945663_insuranc_u_insurance_clients_data');
    insuranceGR.initialize();

    // Map variables to insurance client fields
    if (variables.first_name && variables.last_name) {
        insuranceGR.setValue('client_name', variables.first_name + ' ' + variables.last_name);
    }
    insuranceGR.setValue('contact_email', variables.email || '');
    insuranceGR.setValue('contact_phone', variables.mobile_number || '');
    insuranceGR.setValue('policy_type', variables.policy_type || 'auto');

    // Generate policy number
    var policyNumber = 'POL-' + new GlideDateTime().getNumericValue();
    insuranceGR.setValue('policy_number', policyNumber);

    // Set policy dates
    var startDate = new GlideDateTime();
    insuranceGR.setValue('policy_start_date', startDate.getDisplayValue());

    // Set status
    insuranceGR.setValue('status', 'active');

    var newPolicyId = insuranceGR.insert();

    if (newPolicyId) {
        // Update the catalog request with the policy number
        current.setValue('state', '3'); // Closed Complete
        current.setValue('stage', 'closed_complete');
        var workNotes = 'Policy created successfully. Policy Number: ' + policyNumber + 
                      '\nPolicy ID: ' + newPolicyId;
        current.setWorkNotes(workNotes);

        // Fire welcome event
        gs.eventQueue('insurance.policy.welcome', insuranceGR,
                     insuranceGR.getValue('client_name'),
                     policyNumber,
                     variables.email);

        gs.info('New policy created from catalog submission: ' + policyNumber);
    }
}
